pub fn pack(dst: &mut [u8], args: &PlayerAppearanceInitArgs) -> ProgramResult {
    if dst.len() != Self::LEN {
        return Err(NicechunkPlayerError::InvalidAppearanceData.into());
    }
    Self::validate_model_kind(args.model_kind)?;
    PlayerProfile::validate_name(args.display_name.as_bytes())?;
    Self::validate_title(args.title)?;
    Self::validate_model_code(args.model_code)?;

    let mut writer = ByteWriter { dst, offset: 0 };
    writer.bytes(&PLAYER_APPEARANCE_MAGIC)?;
    writer.u16(PLAYER_APPEARANCE_VERSION)?;
    writer.u8(args.bump)?;
    writer.u8(1)?;
    writer.pubkey(args.owner)?;
    writer.pubkey(args.player_profile)?;
    writer.pubkey(args.global_config)?;
    writer.pubkey(args.treasury_authority)?;
    writer.u8(args.model_kind)?;
    writer.u16(0)?;
    writer.u16(args.display_name.as_bytes().len() as u16)?;
    writer.u16(args.title.len() as u16)?;
    writer.u16(args.model_code.len() as u16)?;
    writer.u8(APPEARANCE_EQUIPMENT_SLOT_COUNT as u8)?;
    writer.u64(args.created_slot)?;
    writer.u64(args.updated_slot)?;
    writer.i64(args.created_at)?;
    writer.i64(args.updated_at)?;
    writer.bytes(&[0_u8; Self::HEADER_LEN - Self::RESERVED_OFFSET])?;

    let display_name_bytes = args.display_name.as_bytes();
    writer.bytes(display_name_bytes)?;
    writer.bytes(
        &[0_u8; PLAYER_NAME_MAX_BYTES][..PLAYER_NAME_MAX_BYTES - display_name_bytes.len()],
    )?;
    writer.bytes(args.title)?;
    writer.bytes(
        &[0_u8; APPEARANCE_TITLE_MAX_BYTES][..APPEARANCE_TITLE_MAX_BYTES - args.title.len()],
    )?;
    writer.bytes(args.model_code)?;
    writer.bytes(
        &[0_u8; APPEARANCE_MODEL_CODE_MAX_BYTES]
            [..APPEARANCE_MODEL_CODE_MAX_BYTES - args.model_code.len()],
    )?;
    for slot in 0..APPEARANCE_EQUIPMENT_SLOT_COUNT {
        writer.u8(0)?;
        writer.u8(slot as u8)?;
        writer.bytes(&[0_u8; APPEARANCE_EQUIPMENT_SLOT_LEN - 2])?;
    }

fn set_equipment_slot(
    program_id: &Pubkey,
    accounts: &[AccountInfo],
    payload: &[u8],
) -> ProgramResult {
    if payload.len() != 2 || (accounts.len() != 3 && accounts.len() != 4) {
        return Err(NicechunkPlayerError::InvalidInstruction.into());
    }

    let account_info_iter = &mut accounts.iter();
    let authority = next_account_info(account_info_iter)?;
    let player_profile = next_account_info(account_info_iter)?;
    let global_config = next_account_info(account_info_iter)?;

    validate_player_write_accounts(program_id, authority, player_profile, global_config)?;
    let slot = payload[0];
    let backpack_index = payload[1];
    let item = if backpack_index == CLEAR_EQUIPMENT_BACKPACK_INDEX {
        if accounts.len() != 3 {
            return Err(NicechunkPlayerError::InvalidAccountCount.into());
        }
        Pubkey::default()
    } else {
        if accounts.len() != 4 {
            return Err(NicechunkPlayerError::InvalidAccountCount.into());
        }
        let backpack = next_account_info(account_info_iter)?;
        if backpack.owner != &NICECHUNK_BACKPACK_PROGRAM_ID
            && backpack.owner != &NICECHUNK_GAME_PROGRAM_ID
        {
            return Err(NicechunkPlayerError::InvalidBackpackProgram.into());
        }
        let backpack_data = backpack.try_borrow_data()?;
        BackpackAccountView::validate_pda_and_owner(
            &backpack_data,
            backpack.key,
            backpack.owner,
            authority.key,
        )?;
        BackpackAccountView::equippable_item_pda_at(&backpack_data, authority.key, backpack_index)?
    };
    let clock = Clock::get()?;
    let mut data = player_profile.try_borrow_mut_data()?;
    PlayerProfile::write_equipment_slot(&mut data, slot, &item, clock.slot)

fn find_backpack_item_slot_by_pda(
    data: &[u8],
    item: &Pubkey,
) -> Result<([u8; BACKPACK_SLOT_RECORD_LEN], u8), solana_program::program_error::ProgramError> {
    let item_count = data[BACKPACK_ITEM_COUNT_OFFSET];
    for index in 0..item_count {
        let offset = BACKPACK_HEADER_LEN + index as usize * BACKPACK_SLOT_RECORD_LEN;
        let slot = &data[offset..offset + BACKPACK_SLOT_RECORD_LEN];
        if slot[0] == BACKPACK_SLOT_KIND_ITEM
            && &slot[BACKPACK_SLOT_ITEM_PDA_OFFSET..BACKPACK_SLOT_ITEM_PDA_OFFSET + 32]
                == item.as_ref()
        {
            return Ok((copy_valid_backpack_slot(slot)?, index));
        }
    }
